<script setup>
import{ref}from'vue';import{onLoad}from'@dcloudio/uni-app';import{api}from'../../api'
const shop=ref(null),saving=ref(false);onLoad(async()=>{try{shop.value=await api.merchantShop()}catch(_){}})
async function save(){if(!shop.value.name.trim()||!shop.value.phone.trim()||!shop.value.address.trim()||!shop.value.businessHours.trim())return uni.showToast({title:'请填写店铺名称、电话、地址和营业时间',icon:'none'});saving.value=true;try{shop.value=await api.updateShop({name:shop.value.name,logoUrl:shop.value.logoUrl||null,phone:shop.value.phone,address:shop.value.address,notice:shop.value.notice||null,businessHours:shop.value.businessHours,deliveryFee:Number(shop.value.deliveryFee),minDeliveryAmount:Number(shop.value.minDeliveryAmount),packageFee:Number(shop.value.packageFee),deliveryRange:shop.value.deliveryRange||null,estimatedDeliveryMinutes:shop.value.estimatedDeliveryMinutes?Number(shop.value.estimatedDeliveryMinutes):null});uni.showToast({title:'保存成功'})}catch(_){}finally{saving.value=false}}
</script>
<template><view v-if="shop" class="page settings-page"><view class="content"><view class="card form-card"><text class="group-title">基础信息</text><view class="field"><text class="field-label">店铺名称 *</text><input v-model="shop.name" class="input"/></view><view class="field"><text class="field-label">联系电话 *</text><input v-model="shop.phone" class="input"/></view><view class="field"><text class="field-label">店铺地址 *</text><input v-model="shop.address" class="input"/></view><view class="field"><text class="field-label">营业时间 *</text><input v-model="shop.businessHours" class="input" placeholder="09:00-22:00"/></view><view class="field"><text class="field-label">店铺公告</text><textarea v-model="shop.notice" class="textarea"/></view></view><view class="card form-card"><text class="group-title">配送设置</text><view class="two"><view class="field"><text class="field-label">起送金额</text><input v-model="shop.minDeliveryAmount" class="input" type="digit"/></view><view class="field"><text class="field-label">配送费</text><input v-model="shop.deliveryFee" class="input" type="digit"/></view></view><view class="two"><view class="field"><text class="field-label">包装费</text><input v-model="shop.packageFee" class="input" type="digit"/></view><view class="field"><text class="field-label">预计配送分钟</text><input v-model="shop.estimatedDeliveryMinutes" class="input" type="number"/></view></view><view class="field"><text class="field-label">配送范围说明</text><textarea v-model="shop.deliveryRange" class="textarea"/></view></view></view><view class="save-bar"><button class="primary-btn" :disabled="saving" @tap="save">{{saving?'保存中…':'保存设置'}}</button></view></view></template>
<style scoped>.settings-page{padding-bottom:130rpx}.form-card{padding:28rpx;margin-bottom:22rpx}.group-title{display:block;margin-bottom:28rpx;font-size:31rpx;font-weight:800}.two{display:flex;gap:20rpx}.two .field{flex:1}.save-bar{position:fixed;left:0;right:0;bottom:0;padding:16rpx 28rpx calc(16rpx + env(safe-area-inset-bottom));background:#fff}.save-bar button{width:100%}</style>
